void gnn_ppo_route_16x16_mesh( const Router *r, const Flit *f, 
         int in_channel, OutputSet *outputs, bool inject )
{
  int vcBegin = 0, vcEnd = gNumVCs-1;
  (void)in_channel;
  int out_port;
  if(inject) {
    out_port = -1;
  } else if(r->GetID() == f->dest) {
    out_port = 2*gN;
  } else {
    int cur = r->GetID();
    int dest = f->dest;
    int route = gnn_route_table_16x16[cur][dest];
    if(route == 0) out_port = dor_next_mesh( cur, dest, false );
    else out_port = dor_next_mesh( cur, dest, true );
  }
  outputs->Clear();
  outputs->AddRange( out_port, vcBegin, vcEnd );
}

